import React, { useState, useEffect } from 'react';
import { ModelProvider, MarketType, AnalysisResult } from '../types';
import { fetchSectorLadderAnalysis } from '../services/geminiService';
import { Layers, Loader2, Search, Zap, AlertTriangle, ShieldCheck, ChevronRight, TrendingUp, TrendingDown, Info, Activity, Flame } from 'lucide-react';

