  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleAnalyze = async () => {
    if (!query) return;
    if (!settings.geminiKey) {
      onOpenSettings();
      return;
    }
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await fetchSectorLadderAnalysis(query, currentMarket, settings.geminiKey);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "分析失败");
    } finally {
      setLoading(false);
    }
  };

  const data = result?.ladderData;

  const getStageColor = (stage: string) => {
    switch (stage) {
      case 'Starting': return 'bg-emerald-500';
      case 'Growing': return 'bg-blue-500';
      case 'Climax': return 'bg-rose-500';
      case 'End': return 'bg-amber-600';
      case 'Receding': return 'bg-slate-600';
      default: return 'bg-slate-400';
    }
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-6xl mx-auto pb-12">
      {/* Search Header */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
        <h2 className="text-2xl font-black text-slate-800 flex items-center gap-3 mb-2">
          <div className="p-2 bg-indigo-600 rounded-lg text-white">
            <Layers className="w-6 h-6" />
          </div>
          板块龙补梯队效能分析
        </h2>
        <p className="text-slate-500 text-sm mb-8">AI 实时扫描板块梯队结构，识别“龙头-补涨”协同性，预判行情末期背离风险。</p>

        <div className="max-w-xl flex gap-3">
          <div className="relative flex-1">
            <input 
              type="text" 
              value={query}
              onChange={e => setQuery(e.target.value)}
              placeholder="输入板块名称 (如: 低空经济, 半导体)..."
              className="w-full h-12 pl-10 pr-4 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
              onKeyDown={(e) => e.key === 'Enter' && handleAnalyze()}
            />
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          </div>
          <button 
            onClick={handleAnalyze}
            disabled={loading || !query}
            className="px-6 h-12 bg-slate-900 text-white rounded-xl font-bold shadow-lg hover:bg-slate-800 transition-all flex items-center gap-2 disabled:opacity-50"
          >
            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Zap className="w-4 h-4" />}
            开始诊断
          </button>
        </div>
      </div>

      {error && (
        <div className="p-4 bg-rose-50 border border-rose-100 rounded-xl text-rose-700 flex items-center gap-3">
          <AlertTriangle className="w-5 h-5" />
          <span className="text-sm font-bold">{error}</span>
