          <div className={`p-8 rounded-3xl text-white shadow-xl relative overflow-hidden ${data.risk_score > 70 ? 'bg-amber-700' : 'bg-indigo-900'}`}>
             <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
                <div>
                  <div className="flex items-center gap-2 mb-2">
                     <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${getStageColor(data.cycle_stage)}`}>{data.stage_label}</span>
                     <span className="text-xs font-bold opacity-60">板块生命周期评估</span>
                  </div>
